# scripts/check_deps_policy.py — run in CI gate
import tomllib, yaml, sys, re
from pathlib import Path

def load_approved(policy_path: str) -> dict:
    with open(policy_path) as f:
        policy = yaml.safe_load(f)
    approved = {p["package"]: p for p in policy.get("approved", [])}
    blocked = {p["package"]: p for p in policy.get("blocked", [])}
    return approved, blocked

def parse_requirements(req_path: str) -> list[tuple[str, str]]:
    deps = []
    for line in Path(req_path).read_text().splitlines():
        line = line.strip()
        if line and not line.startswith("#"):
            match = re.match(r"([a-zA-Z0-9_-]+)[>=<~!]+([0-9.]+)", line)
            if match:
                deps.append((match.group(1).lower(), match.group(2)))
    return deps

def check(policy_path, requirements_path):
    approved, blocked = load_approved(policy_path)
    deps = parse_requirements(requirements_path)
    violations = []
    for pkg, version in deps:
        if pkg in blocked:
            violations.append(f"BLOCKED: {pkg} — {blocked[pkg]['reason']}")
        elif pkg not in approved and not pkg.startswith("-"):
            violations.append(f"NOT APPROVED: {pkg}=={version} — submit approval PR")
    return violations

if __name__ == "__main__":
    violations = check("deps-policy.yaml", "requirements.txt")
    if violations:
        print("Dependency policy violations:")
        for v in violations:
            print(f"  {v}")
        sys.exit(1)
    print("All dependencies approved.")
